import { NextResponse } from "next/server";
import { db } from "@/lib/firebase-admin";

export async function GET() {
  try {
    const snapshot = await db.collection("expenses").orderBy("createdAt", "desc").get();
    
    const expenses: any[] = [];
    snapshot.forEach((doc) => {
      // Convert timestamps to string/Date for client
      const data = doc.data();
      expenses.push({ 
        id: doc.id, 
        ...data,
        createdAt: data.createdAt?.toDate?.()?.toISOString() || new Date().toISOString()
      });
    });

    return NextResponse.json({ expenses });
  } catch (error: any) {
    console.error("Error fetching admin expenses:", error);
    return NextResponse.json({ error: error.message || "Failed to load expenses securely" }, { status: 500 });
  }
}
